/**
 * Operator Ω · Surface Tuning Map (MVP).
 *
 * Flat catalog of every constant/enum/heuristic that shapes the solution
 * surface. Each entry is annotated along 2D push axes (diversity vs accuracy)
 * and a coupling class (runtime / prompt / structural) so an operator can
 * reason about *which* knob to turn and *what else* must change when they
 * do. This registry is documentation; it is NOT consumed at runtime.
 *
 * Workflow: edit the underlying constant at `location`, bump any prompt
 * version if coupling === "prompt", then re-run the validation matrix to
 * confirm the surface shifted as intended.
 */

export type SurfaceAxis =
  | "active_agent_set"
  | "overlay_tokens"
  | "workflow_tasks"
  | "bundle_allocation_l1"
  | "connector_set"
  | "dry_run_gates"
  | "mc_winner"
  | "mc_projection_l2";

export type TuningPhase = "phase-2" | "phase-3" | "phase-4" | "finalize";

export type Coupling = "runtime" | "prompt" | "structural";

export type Pull = -2 | -1 | 0 | 1 | 2;

export type ValueKind =
  | "number"
  | "vector"
  | "set"
  | "enum"
  | "keyword_list"
  | "template";

export interface Tunable {
  /** Stable machine id used in `// @tunable <id>` annotations. */
  id: string;
  /** Which of the 8 solution-surface axes this knob shapes. */
  axis: SurfaceAxis;
  /** Onboarding phase that consumes this value. */
  phase: TuningPhase;
  /** Repo-relative source location. Line numbers may drift — grep for id. */
  location: string;
  /** One-line purpose. */
  description: string;
  valueKind: ValueKind;
  /** Stringified default (for display). */
  currentValue: string;
  /** Does raising this value widen per-operator variation? */
  diversityPull: Pull;
  /** Does raising this value make outputs more faithful to operator inputs? */
  accuracyPull: Pull;
  coupling: Coupling;
  /** Prose range known to keep the system healthy. */
  safeRange?: string;
  /** What breaks if moved too far / in the wrong direction. */
  risk?: string;
}

